class UserpassAuthBackend(AuthBackend):
    """Username/password backend with salted PBKDF2 hashes."""

    def __init__(
        self,
        name: str = "userpass",
        enabled: bool = True,
        iterations: int = 200_000,
        default_ttl: float = 3600.0,
    ) -> None:
        super().__init__(name=name, enabled=enabled)
        if iterations <= 0:
            raise AuthenticationError("password hash iterations must be positive")
        if default_ttl < 0:
            raise AuthenticationError("default ttl must be non-negative")
        self.iterations = iterations
        self.default_ttl = default_ttl
        self._users: dict[str, UserpassUser] = {}

    def create_user(
        self,
        username: str,
        password: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        entity_id: str | None = None,
        disabled: bool = False,
    ) -> UserpassUser:
        if not username or not password:
            raise AuthenticationError("username and password are required")
        if username in self._users:
            raise AuthenticationError(f"user already exists: {username}")
        user_ttl = self.default_ttl if ttl is None else ttl
        if user_ttl < 0:
            raise AuthenticationError("ttl must be non-negative")
        salt = generate_salt()
        user = UserpassUser(
            username=username,
            password_hash=self._hash_password(password, salt),
            salt=salt,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=user_ttl,
            entity_id=entity_id,
            disabled=disabled,
        )
        self._users[username] = user
        return user

    def delete_user(self, username: str) -> bool:
        return self._users.pop(username, None) is not None

    def get_user(self, username: str) -> UserpassUser | None:
        return self._users.get(username)

    def list_users(self) -> list[str]:
        return sorted(self._users)

    def set_password(self, username: str, password: str) -> UserpassUser:
        if not password:
            raise AuthenticationError("password is required")
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError(f"user not found: {username}")
        user.salt = generate_salt()
        user.password_hash = self._hash_password(password, user.salt)
        return user

    def disable_user(self, username: str) -> None:
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError(f"user not found: {username}")
        user.disabled = True

    def enable_user(self, username: str) -> None:
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError(f"user not found: {username}")
        user.disabled = False

    def authenticate(self, **credentials: Any) -> AuthResult:
        self.require_enabled()
        username = credentials.get("username")
        password = credentials.get("password")
        if not isinstance(username, str) or not isinstance(password, str):
            raise AuthenticationError("missing username or password")

        user = self._users.get(username)
        if user is None or not self._verify_password(password, user):
            raise AuthenticationError("invalid username or password")
        if user.disabled:
            raise AuthenticationError("user is disabled", details={"username": username})

        metadata = dict(user.metadata)
        metadata.setdefault("username", username)
        return AuthResult(
            backend=self.name,
            identity=username,
            policies=list(user.policies),
            metadata=metadata,
            ttl=user.ttl,
            entity_id=user.entity_id,
        )

    def _hash_password(self, password: str, salt: bytes) -> str:
        digest = hashlib.pbkdf2_hmac(
            "sha256",
            password.encode("utf-8"),
            salt,
            self.iterations,
        )
        return digest.hex()

    def _verify_password(self, password: str, user: UserpassUser) -> bool:
        candidate = self._hash_password(password, user.salt)
        return hmac.compare_digest(candidate, user.password_hash)


@dataclass
class AppRoleSecretID:
    """Secret ID bound to an AppRole."""

    secret_id: str
    accessor: str
    created_at: float = field(default_factory=time.time)
    ttl: float = 0.0
    num_uses: int = 0
    uses_remaining: int = 0
    metadata: dict[str, str] = field(default_factory=dict)

    def __post_init__(self) -> None:
        if self.num_uses > 0 and self.uses_remaining == 0:
            self.uses_remaining = self.num_uses

    def is_expired(self, now: float | None = None) -> bool:
        if self.ttl <= 0:
            return False
        current = time.time() if now is None else now
        return current >= self.created_at + self.ttl

    def is_valid(self, now: float | None = None) -> bool:
        if self.is_expired(now):
            return False
        return self.num_uses <= 0 or self.uses_remaining > 0

    def use(self) -> None:
        if self.num_uses <= 0:
            return
        if self.uses_remaining <= 0:
            raise AuthenticationError("secret id has no remaining uses")
        self.uses_remaining -= 1

    def to_dict(self) -> dict[str, Any]:
        return {
            "accessor": self.accessor,
            "created_at": self.created_at,
            "ttl": self.ttl,
            "num_uses": self.num_uses,
            "uses_remaining": self.uses_remaining,
            "metadata": dict(self.metadata),
        }


