class AppRoleAuthBackend(AuthBackend):
    """AppRole backend using generated role IDs and secret IDs."""

    def __init__(
        self,
        name: str = "approle",
        enabled: bool = True,
        default_ttl: float = 3600.0,
    ) -> None:
        super().__init__(name=name, enabled=enabled)
        if default_ttl < 0:
            raise AuthenticationError("default ttl must be non-negative")
        self.default_ttl = default_ttl
        self._roles: dict[str, AppRole] = {}

    def create_role(
        self,
        name: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        secret_id_ttl: float = 0.0,
        secret_id_num_uses: int = 0,
        entity_id: str | None = None,
        role_id: str | None = None,
        disabled: bool = False,
    ) -> AppRole:
        if not name:
            raise AuthenticationError("role name is required")
        if name in self._roles:
            raise AuthenticationError(f"role already exists: {name}")
        role_ttl = self.default_ttl if ttl is None else ttl
        if role_ttl < 0 or secret_id_ttl < 0 or secret_id_num_uses < 0:
            raise AuthenticationError("ttl and use limits must be non-negative")
        role = AppRole(
            name=name,
            role_id=role_id or generate_id("role", 24),
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=role_ttl,
            secret_id_ttl=secret_id_ttl,
            secret_id_num_uses=secret_id_num_uses,
            entity_id=entity_id,
            disabled=disabled,
        )
        self._roles[name] = role
        return role

    def delete_role(self, name: str) -> bool:
        return self._roles.pop(name, None) is not None

    def get_role(self, name: str) -> AppRole | None:
        return self._roles.get(name)

    def list_roles(self) -> list[str]:
        return sorted(self._roles)

    def disable_role(self, name: str) -> None:
        role = self._roles.get(name)
        if role is None:
            raise AuthenticationError(f"role not found: {name}")
        role.disabled = True

    def enable_role(self, name: str) -> None:
        role = self._roles.get(name)
        if role is None:
            raise AuthenticationError(f"role not found: {name}")
        role.disabled = False

    def generate_secret_id(
        self,
        role_name: str,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        num_uses: int | None = None,
    ) -> AppRoleSecretID:
        role = self._roles.get(role_name)
        if role is None:
            raise AuthenticationError(f"role not found: {role_name}")
        secret_ttl = role.secret_id_ttl if ttl is None else ttl
        secret_num_uses = role.secret_id_num_uses if num_uses is None else num_uses
        if secret_ttl < 0 or secret_num_uses < 0:
            raise AuthenticationError("ttl and use limits must be non-negative")
        secret = AppRoleSecretID(
            secret_id=generate_token(32),
            accessor=generate_id("sid", 12),
            ttl=secret_ttl,
            num_uses=secret_num_uses,
            metadata=dict(metadata or {}),
        )
        role.secret_ids[secret.secret_id] = secret
        return secret

    def list_secret_id_accessors(self, role_name: str) -> list[str]:
        role = self._roles.get(role_name)
        if role is None:
            raise AuthenticationError(f"role not found: {role_name}")
        return sorted(secret.accessor for secret in role.secret_ids.values())

    def authenticate(self, **credentials: Any) -> AuthResult:
        self.require_enabled()
        role_id = credentials.get("role_id")
        secret_id = credentials.get("secret_id")
        if not isinstance(role_id, str) or not isinstance(secret_id, str):
            raise AuthenticationError("missing role_id or secret_id")

        role = self._find_role_by_id(role_id)
        if role is None:
            raise AuthenticationError("invalid role_id or secret_id")
        if role.disabled:
            raise AuthenticationError("role is disabled", details={"role": role.name})

        secret = self._find_secret_id(role, secret_id)
        if secret is None or not secret.is_valid():
            raise AuthenticationError("invalid role_id or secret_id")
        secret.use()

        metadata = dict(role.metadata)
        metadata.update(secret.metadata)
        metadata.setdefault("role_name", role.name)
        metadata.setdefault("secret_id_accessor", secret.accessor)
        return AuthResult(
            backend=self.name,
            identity=role.name,
            policies=list(role.policies),
            metadata=metadata,
            ttl=role.ttl,
            entity_id=role.entity_id,
        )

    def _find_role_by_id(self, role_id: str) -> AppRole | None:
        for role in self._roles.values():
            if hmac.compare_digest(role.role_id, role_id):
                return role
        return None

    def _find_secret_id(self, role: AppRole, secret_id: str) -> AppRoleSecretID | None:
        for secret in role.secret_ids.values():
            if hmac.compare_digest(secret.secret_id, secret_id):
                return secret
        return None


