class CertificateAuthBackend(AuthBackend):
    """Certificate fingerprint backend."""

    def __init__(
        self,
        name: str = "cert",
        enabled: bool = True,
        default_ttl: float = 3600.0,
    ) -> None:
        super().__init__(name=name, enabled=enabled)
        if default_ttl < 0:
            raise AuthenticationError("default ttl must be non-negative")
        self.default_ttl = default_ttl
        self._certificates: dict[str, CertificateIdentity] = {}
        self._fingerprint_index: dict[str, str] = {}

    def add_certificate(
        self,
        name: str,
        fingerprint: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        entity_id: str | None = None,
        disabled: bool = False,
    ) -> CertificateIdentity:
        if not name or not fingerprint:
            raise AuthenticationError("certificate name and fingerprint are required")
        normalized = normalize_fingerprint(fingerprint)
        if name in self._certificates:
            raise AuthenticationError(f"certificate already exists: {name}")
        if normalized in self._fingerprint_index:
            raise AuthenticationError("certificate fingerprint already exists")
        cert_ttl = self.default_ttl if ttl is None else ttl
        if cert_ttl < 0:
            raise AuthenticationError("ttl must be non-negative")
        certificate = CertificateIdentity(
            name=name,
            fingerprint=normalized,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=cert_ttl,
            entity_id=entity_id,
            disabled=disabled,
        )
        self._certificates[name] = certificate
        self._fingerprint_index[normalized] = name
        return certificate

    def delete_certificate(self, name: str) -> bool:
        certificate = self._certificates.pop(name, None)
        if certificate is None:
            return False
        self._fingerprint_index.pop(certificate.fingerprint, None)
        return True

    def get_certificate(self, name: str) -> CertificateIdentity | None:
        return self._certificates.get(name)

    def list_certificates(self) -> list[str]:
        return sorted(self._certificates)

    def disable_certificate(self, name: str) -> None:
        certificate = self._certificates.get(name)
        if certificate is None:
            raise AuthenticationError(f"certificate not found: {name}")
        certificate.disabled = True

    def enable_certificate(self, name: str) -> None:
        certificate = self._certificates.get(name)
        if certificate is None:
            raise AuthenticationError(f"certificate not found: {name}")
        certificate.disabled = False

    def authenticate(self, **credentials: Any) -> AuthResult:
        self.require_enabled()
        fingerprint = credentials.get("fingerprint", credentials.get("certificate_fingerprint"))
        if not isinstance(fingerprint, str):
            raise AuthenticationError("missing certificate fingerprint")
        normalized = normalize_fingerprint(fingerprint)

        certificate = self._find_certificate(normalized)
        if certificate is None:
            raise AuthenticationError("invalid certificate fingerprint")
        if certificate.disabled:
            raise AuthenticationError("certificate is disabled", details={"certificate": certificate.name})

        metadata = dict(certificate.metadata)
        metadata.setdefault("certificate_name", certificate.name)
        return AuthResult(
            backend=self.name,
            identity=certificate.name,
            policies=list(certificate.policies),
            metadata=metadata,
            ttl=certificate.ttl,
            entity_id=certificate.entity_id,
        )

    def _find_certificate(self, fingerprint: str) -> CertificateIdentity | None:
        for stored, name in self._fingerprint_index.items():
            if hmac.compare_digest(stored, fingerprint):
                return self._certificates.get(name)
        return None


class TokenAuthBackend(AuthBackend):
    """Token backend that validates already-issued tokens."""

    def __init__(self, token_store: TokenStore, name: str = "token", enabled: bool = True) -> None:
        super().__init__(name=name, enabled=enabled)
        self.token_store = token_store

    def authenticate(self, **credentials: Any) -> AuthResult:
        self.require_enabled()
        token_id = credentials.get("token", credentials.get("token_id"))
        if not isinstance(token_id, str):
            raise AuthenticationError("missing token")
        try:
            token = self.token_store.lookup(token_id)
            token.use()
        except TokenError as exc:
            raise AuthenticationError("invalid token", details={"reason": exc.code}) from exc

        metadata = dict(token.metadata)
        metadata.setdefault("accessor", token.accessor)
        metadata.setdefault("token_type", token.token_type.value)
        return AuthResult(
            backend=self.name,
            identity=token.entity_id or token.accessor,
            policies=list(token.policies),
            metadata=metadata,
            ttl=token.remaining_ttl,
            entity_id=token.entity_id,
            token_id=token.token_id,
            renewable=token.renewable,
        )


class AuthManager:
    """Registers auth backends and dispatches authentication requests."""

    def __init__(self) -> None:
        self._backends: dict[str, AuthBackend] = {}

    def register_backend(self, backend: AuthBackend, name: str | None = None) -> AuthBackend:
        backend_name = name or backend.name
        if not backend_name:
            raise AuthenticationError("auth backend name is required")
        if backend_name in self._backends:
            raise AuthenticationError(f"auth backend already registered: {backend_name}")
        backend.name = backend_name
        self._backends[backend_name] = backend
        return backend

    def unregister_backend(self, name: str) -> bool:
        return self._backends.pop(name, None) is not None

    def get_backend(self, name: str) -> AuthBackend | None:
        return self._backends.get(name)

    def list_backends(self) -> list[str]:
        return sorted(self._backends)

    def enabled_backends(self) -> list[str]:
        return sorted(name for name, backend in self._backends.items() if backend.enabled)

    def enable_backend(self, name: str) -> None:
        backend = self._get_required_backend(name)
        backend.enable()

    def disable_backend(self, name: str) -> None:
        backend = self._get_required_backend(name)
        backend.disable()

    def authenticate(self, backend_name: str, **credentials: Any) -> AuthResult:
        backend = self._get_required_backend(backend_name)
        backend.require_enabled()
        return backend.authenticate(**credentials)

    def _get_required_backend(self, name: str) -> AuthBackend:
        backend = self._backends.get(name)
        if backend is None:
            raise AuthenticationError("unknown auth backend", details={"backend": name})
        return backend


@dataclass
class RateLimitState:
    """Observable state for one rate-limit key."""

    key: str
    failures: int
    locked_until: float = 0.0

    def is_locked(self, now: float | None = None) -> bool:
        current = time.time() if now is None else now
        return self.locked_until > current


class AuthRateLimiter:
    """Small fixed-window rate limiter for auth attempts."""

    def __init__(
        self,
        max_attempts: int = 5,
        window: float = 60.0,
        lockout: float = 300.0,
        clock: Clock = time.time,
    ) -> None:
        if max_attempts <= 0 or window <= 0 or lockout < 0:
            raise ValueError("rate limit values must be positive")
        self.max_attempts = max_attempts
        self.window = window
        self.lockout = lockout
        self._clock = clock
        self._failures: dict[str, list[float]] = {}
        self._locked_until: dict[str, float] = {}

    def check_allowed(self, key: str, now: float | None = None) -> None:
        if self.is_limited(key, now=now):
            raise AuthenticationError("too many authentication attempts", details={"key": key})

    def record_failure(self, key: str, now: float | None = None) -> RateLimitState:
        current = self._now(now)
        failures = self._recent_failures(key, current)
        failures.append(current)
        self._failures[key] = failures
        if len(failures) >= self.max_attempts:
            self._locked_until[key] = current + self.lockout
        return self.get_state(key, now=current)

    def record_success(self, key: str) -> None:
        self.reset(key)

    def reset(self, key: str) -> None:
        self._failures.pop(key, None)
        self._locked_until.pop(key, None)

    def is_limited(self, key: str, now: float | None = None) -> bool:
        current = self._now(now)
        locked_until = self._locked_until.get(key, 0.0)
        if locked_until > current:
            return True
        if locked_until:
            self._locked_until.pop(key, None)
        self._failures[key] = self._recent_failures(key, current)
        return False

    def remaining_attempts(self, key: str, now: float | None = None) -> int:
        if self.is_limited(key, now=now):
            return 0
        current = self._now(now)
        return max(0, self.max_attempts - len(self._recent_failures(key, current)))

    def get_state(self, key: str, now: float | None = None) -> RateLimitState:
        current = self._now(now)
        return RateLimitState(
            key=key,
            failures=len(self._recent_failures(key, current)),
            locked_until=self._locked_until.get(key, 0.0),
        )

    def _recent_failures(self, key: str, now: float) -> list[float]:
        cutoff = now - self.window
        return [timestamp for timestamp in self._failures.get(key, []) if timestamp >= cutoff]

    def _now(self, now: float | None = None) -> float:
        return self._clock() if now is None else now


@dataclass
class AuthSession:
    """Tracked authenticated session."""

    session_id: str
    backend: str
    identity: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    entity_id: str | None = None
    token_id: str | None = None
    created_at: float = field(default_factory=time.time)
    expires_at: float = 0.0
    last_seen: float = field(default_factory=time.time)
    revoked: bool = False

    def is_expired(self, now: float | None = None) -> bool:
        if self.expires_at <= 0:
            return False
        current = time.time() if now is None else now
        return current >= self.expires_at

    def is_active(self, now: float | None = None) -> bool:
        return not self.revoked and not self.is_expired(now)

    def touch(self, now: float | None = None) -> None:
        self.last_seen = time.time() if now is None else now

    def revoke(self) -> None:
        self.revoked = True

    def to_dict(self) -> dict[str, Any]:
        return {
            "session_id": self.session_id,
            "backend": self.backend,
            "identity": self.identity,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "entity_id": self.entity_id,
            "token_id": self.token_id,
            "created_at": self.created_at,
            "expires_at": self.expires_at,
            "last_seen": self.last_seen,
            "revoked": self.revoked,
        }


class AuthSessionTracker:
    """In-memory authenticated session tracker."""

    def __init__(self, default_ttl: float = 3600.0, clock: Clock = time.time) -> None:
        if default_ttl < 0:
            raise ValueError("default ttl must be non-negative")
        self.default_ttl = default_ttl
        self._clock = clock
        self._sessions: dict[str, AuthSession] = {}

    def create_session(
        self,
        result: AuthResult,
        ttl: float | None = None,
        now: float | None = None,
    ) -> AuthSession:
        current = self._now(now)
        session_ttl = result.ttl if ttl is None else ttl
        if session_ttl < 0:
            raise AuthenticationError("session ttl must be non-negative")
        if session_ttl == 0:
            session_ttl = self.default_ttl
        expires_at = 0.0 if session_ttl == 0 else current + session_ttl
        session = AuthSession(
            session_id=generate_id("sess", 24),
            backend=result.backend,
            identity=result.identity,
            policies=list(result.policies),
            metadata=dict(result.metadata),
            entity_id=result.entity_id,
            token_id=result.token_id,
            created_at=current,
            expires_at=expires_at,
            last_seen=current,
        )
        self._sessions[session.session_id] = session
        return session

    def get_session(self, session_id: str) -> AuthSession | None:
        return self._sessions.get(session_id)

    def validate_session(self, session_id: str, now: float | None = None) -> AuthSession:
        current = self._now(now)
        session = self._sessions.get(session_id)
        if session is None:
            raise AuthenticationError("session not found")
        if session.revoked:
            raise AuthenticationError("session is revoked")
        if session.is_expired(current):
            raise AuthenticationError("session is expired")
        session.touch(current)
        return session

    def revoke_session(self, session_id: str) -> bool:
        session = self._sessions.get(session_id)
        if session is None:
            return False
        session.revoke()
        return True

    def revoke_identity(self, identity: str) -> int:
        count = 0
        for session in self._sessions.values():
            if session.identity == identity and not session.revoked:
                session.revoke()
                count += 1
        return count

    def list_sessions(
        self,
        identity: str | None = None,
        active_only: bool = True,
        now: float | None = None,
    ) -> list[AuthSession]:
        current = self._now(now)
        sessions = self._sessions.values()
        if identity is not None:
            sessions = [session for session in sessions if session.identity == identity]
        if active_only:
            sessions = [session for session in sessions if session.is_active(current)]
        return sorted(sessions, key=lambda session: session.session_id)

    def cleanup_expired(self, now: float | None = None) -> int:
        current = self._now(now)
        expired = [
            session_id
            for session_id, session in self._sessions.items()
            if session.revoked or session.is_expired(current)
        ]
        for session_id in expired:
            self._sessions.pop(session_id, None)
        return len(expired)

    def _now(self, now: float | None = None) -> float:
        return self._clock() if now is None else now


@dataclass
class MFAChallenge:
    """In-memory MFA challenge."""

    challenge_id: str
    identity: str
    factor: str
    code: str
    created_at: float = field(default_factory=time.time)
    expires_at: float = 0.0
    attempts: int = 0
    max_attempts: int = 3
    verified: bool = False
    metadata: dict[str, str] = field(default_factory=dict)

    def is_expired(self, now: float | None = None) -> bool:
        if self.expires_at <= 0:
            return False
        current = time.time() if now is None else now
        return current >= self.expires_at

    def is_active(self, now: float | None = None) -> bool:
        return not self.verified and self.attempts < self.max_attempts and not self.is_expired(now)

    def to_dict(self) -> dict[str, Any]:
        return {
            "challenge_id": self.challenge_id,
            "identity": self.identity,
            "factor": self.factor,
            "created_at": self.created_at,
            "expires_at": self.expires_at,
