class MFAChallengeStore:
    """Creates and verifies deterministic in-memory MFA challenges."""

    def __init__(
        self,
        ttl: float = 300.0,
        code_length: int = 6,
        max_attempts: int = 3,
        clock: Clock = time.time,
    ) -> None:
        if ttl < 0 or code_length <= 0 or max_attempts <= 0:
            raise ValueError("mfa challenge settings must be positive")
        self.ttl = ttl
        self.code_length = code_length
        self.max_attempts = max_attempts
        self._clock = clock
        self._challenges: dict[str, MFAChallenge] = {}

    def create_challenge(
        self,
        identity: str,
        factor: str = "otp",
        code: str | None = None,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> MFAChallenge:
        if not identity:
            raise AuthenticationError("mfa identity is required")
        current = self._now(now)
        challenge_code = code or self._generate_code()
        challenge = MFAChallenge(
            challenge_id=generate_id("mfa", 20),
            identity=identity,
            factor=factor,
            code=challenge_code,
            created_at=current,
            expires_at=0.0 if self.ttl == 0 else current + self.ttl,
            max_attempts=self.max_attempts,
            metadata=dict(metadata or {}),
        )
        self._challenges[challenge.challenge_id] = challenge
        return challenge

    def verify(self, challenge_id: str, code: str, now: float | None = None) -> MFAChallenge:
        current = self._now(now)
        challenge = self._challenges.get(challenge_id)
        if challenge is None:
            raise AuthenticationError("mfa challenge not found")
        if challenge.verified:
            raise AuthenticationError("mfa challenge already verified")
        if challenge.is_expired(current):
            raise AuthenticationError("mfa challenge expired")
        if challenge.attempts >= challenge.max_attempts:
            raise AuthenticationError("mfa challenge attempts exceeded")

        if not hmac.compare_digest(challenge.code, code):
            challenge.attempts += 1
            raise AuthenticationError("invalid mfa code")

        challenge.verified = True
        return challenge

    def get_challenge(self, challenge_id: str) -> MFAChallenge | None:
        return self._challenges.get(challenge_id)

    def list_challenges(
        self,
        identity: str | None = None,
        active_only: bool = True,
        now: float | None = None,
    ) -> list[MFAChallenge]:
        current = self._now(now)
        challenges = self._challenges.values()
        if identity is not None:
            challenges = [challenge for challenge in challenges if challenge.identity == identity]
        if active_only:
            challenges = [challenge for challenge in challenges if challenge.is_active(current)]
        return sorted(challenges, key=lambda challenge: challenge.challenge_id)

    def cleanup_expired(self, now: float | None = None) -> int:
        current = self._now(now)
        expired = [
            challenge_id
            for challenge_id, challenge in self._challenges.items()
            if challenge.verified or challenge.is_expired(current)
        ]
        for challenge_id in expired:
            self._challenges.pop(challenge_id, None)
        return len(expired)

    def _generate_code(self) -> str:
        upper_bound = (10**self.code_length) - 1
        return str(secure_random_int(0, upper_bound)).zfill(self.code_length)

    def _now(self, now: float | None = None) -> float:
        return self._clock() if now is None else now


