class AuthEventLogger:
    """Bounded in-memory authentication event log."""

    def __init__(self, max_entries: int = 10000, clock: Clock = time.time) -> None:
        if max_entries <= 0:
            raise ValueError("max_entries must be positive")
        self.max_entries = max_entries
        self._clock = clock
        self._events: list[AuthEvent] = []

    def log(
        self,
        event: str,
        backend: str = "",
        identity: str = "",
        success: bool = True,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> AuthEvent:
        auth_event = AuthEvent(
            event_id=generate_id("auth", 16),
            event=event,
            backend=backend,
            identity=identity,
            success=success,
            timestamp=self._now(now),
            metadata=dict(metadata or {}),
        )
        if len(self._events) >= self.max_entries:
            self._events.pop(0)
        self._events.append(auth_event)
        return auth_event

    def get_events(
        self,
        backend: str | None = None,
        identity: str | None = None,
        event: str | None = None,
        success: bool | None = None,
        since: float = 0.0,
    ) -> list[AuthEvent]:
        events = self._events
        if backend is not None:
            events = [auth_event for auth_event in events if auth_event.backend == backend]
        if identity is not None:
            events = [auth_event for auth_event in events if auth_event.identity == identity]
        if event is not None:
            events = [auth_event for auth_event in events if auth_event.event == event]
        if success is not None:
            events = [auth_event for auth_event in events if auth_event.success == success]
        if since:
            events = [auth_event for auth_event in events if auth_event.timestamp >= since]
        return list(events)

    @property
    def total_events(self) -> int:
        return len(self._events)

    def clear(self) -> None:
        self._events.clear()

    def _now(self, now: float | None = None) -> float:
        return self._clock() if now is None else now


