class AuthConfigValidator:
    """Lightweight auth configuration validator."""

    SUPPORTED_BACKENDS = {"userpass", "approle", "cert", "token"}

    def validate(self, config: Mapping[str, Any]) -> AuthConfigValidationResult:
        errors: list[str] = []
        warnings: list[str] = []
        normalized: dict[str, Any] = {}

        if not isinstance(config, Mapping):
            return AuthConfigValidationResult(errors=["config must be a mapping"])

        backends = config.get("backends", {})
        if not isinstance(backends, Mapping):
            errors.append("backends must be a mapping")
            backends = {}

        normalized_backends: dict[str, dict[str, Any]] = {}
        for name, backend_config in sorted(backends.items()):
            if not isinstance(name, str) or not name:
                errors.append("backend names must be non-empty strings")
                continue
            if not isinstance(backend_config, Mapping):
                errors.append(f"backend {name} must be a mapping")
                continue

            backend_type = backend_config.get("type", name)
            if not isinstance(backend_type, str):
                errors.append(f"backend {name} type must be a string")
                continue
            if backend_type not in self.SUPPORTED_BACKENDS:
                errors.append(f"unsupported auth backend type: {backend_type}")

            enabled = backend_config.get("enabled", True)
            if not isinstance(enabled, bool):
                errors.append(f"backend {name} enabled must be boolean")

            ttl = backend_config.get("ttl", backend_config.get("default_ttl", 3600.0))
            if not _is_non_negative_number(ttl):
                errors.append(f"backend {name} ttl must be non-negative")

            normalized_backends[name] = {
                "type": backend_type,
                "enabled": enabled,
                "ttl": ttl,
            }

        if not normalized_backends:
            warnings.append("no auth backends configured")

        self._validate_rate_limit(config.get("rate_limit", {}), errors)
        self._validate_sessions(config.get("sessions", {}), errors)
        self._validate_mfa(config.get("mfa", {}), errors)

        normalized["backends"] = normalized_backends
        return AuthConfigValidationResult(
            errors=errors,
            warnings=warnings,
            normalized=normalized,
        )

    def _validate_rate_limit(self, value: Any, errors: list[str]) -> None:
        if not value:
            return
        if not isinstance(value, Mapping):
            errors.append("rate_limit must be a mapping")
            return
        for key in ("max_attempts", "window", "lockout"):
            if key in value and not _is_non_negative_number(value[key]):
                errors.append(f"rate_limit {key} must be non-negative")

    def _validate_sessions(self, value: Any, errors: list[str]) -> None:
        if not value:
            return
        if not isinstance(value, Mapping):
            errors.append("sessions must be a mapping")
            return
        if "ttl" in value and not _is_non_negative_number(value["ttl"]):
            errors.append("sessions ttl must be non-negative")

    def _validate_mfa(self, value: Any, errors: list[str]) -> None:
        if not value:
            return
        if not isinstance(value, Mapping):
            errors.append("mfa must be a mapping")
            return
        for key in ("ttl", "code_length", "max_attempts"):
            if key in value and not _is_non_negative_number(value[key]):
                errors.append(f"mfa {key} must be non-negative")


def validate_auth_config(config: Mapping[str, Any]) -> AuthConfigValidationResult:
    """Validate an auth configuration mapping."""

    return AuthConfigValidator().validate(config)


def normalize_fingerprint(fingerprint: str) -> str:
    """Normalize common hex certificate fingerprint formats."""

    value = fingerprint.strip().lower()
    for prefix in ("sha256:", "sha1:"):
        if value.startswith(prefix):
            value = value[len(prefix) :]
            break
    return "".join(ch for ch in value if ch not in {":", " ", "-", "\n", "\t"})


def _is_non_negative_number(value: Any) -> bool:
    return isinstance(value, int | float) and value >= 0


